INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (1, 0, "その頃わたくしは、\nスカウトをお受けしておりました。\nミサト様いわく、わたくしには保育士の\n『天賦の才』があるそうで。", 0, 1, 0, 10, 11, 82, 82013, 1);
INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (0, "", "", "", "", "", 0, 91, 82, 82014, 0);
